// ════════════════════════════════════════════
// WhatsApp Bot — Process All Message Types
// ════════════════════════════════════════════
const payload     = $json.body || {};
const data        = payload.data || {};
const sessionId   = payload.sessionId || '';
const msgType     = (data.type || 'chat').toLowerCase();
const from        = data.from || '';
const phoneNumber = from.replace('@c.us', '');
const body        = data.body || '';
const mediaUrl    = data.mediaUrl || null;
const fileName    = data.fileName || null;
const caption     = data.caption || '';
const lat         = data.lat || null;
const lng         = data.lng || null;
const loc         = data.loc || '';

function text(msg) {
  return { sessionId, phoneNumber, endpoint: 'text',
           requestBody: JSON.stringify({ number: phoneNumber, message: msg }) };
}

// ── Echo / Ping mode ──────────────────────────────────
if (msgType === 'chat') {
  const lower = body.toLowerCase();
  const isEchoAr = body.startsWith('صدى');
  const isEchoEn = lower.startsWith('echo');

  if (isEchoAr || isEchoEn) {
    const prefix  = isEchoAr ? 'صدى' : 'Echo';
    const content = body.replace(/^(صدى|echo)\s*/i, '').trim() || '(رسالة فارغة)';
    return [text(`🔁 ${prefix}: ${content}`)];
  }

  // Keyword matching
  let reply;
  const kw = lower;
  if (['مرحبا','هلا','hello','hi','السلام','اهلا','سلام'].some(w => kw.includes(w))) {
    reply = 'أهلاً وسهلاً! 👋 كيف يمكنني مساعدتك؟';
  } else if (['سعر','price','كم تكلف','تكلفة','أسعار'].some(w => kw.includes(w))) {
    reply = 'يرجى التواصل مع فريق المبيعات للاستفسار عن الأسعار 📋';
  } else if (['وقت','دوام','hours','ساعات','متى تفتح'].some(w => kw.includes(w))) {
    reply = 'أوقات العمل: الأحد – الخميس 9 صباحاً – 6 مساءً 🕘';
  } else if (['مساعدة','help','مساعده'].some(w => kw.includes(w))) {
    reply = 'يمكنني مساعدتك! 🤝\nأرسل "صدى <رسالة>" لاختبار البوت.';
  } else {
    reply = 'شكراً لتواصلك! سنرد عليك قريباً. 🙏';
  }
  return [text(reply)];
}

// ── Image ─────────────────────────────────────────────
if (msgType === 'image') {
  const msg = caption
    ? `تم استلام صورتك 📷 — ${caption}`
    : 'تم استلام صورتك 📷\nImage received 📷';
  return [text(msg)];
}

// ── Video ─────────────────────────────────────────────
if (msgType === 'video') {
  const msg = caption
    ? `تم استلام الفيديو 🎬 — ${caption}`
    : 'تم استلام الفيديو 🎬\nVideo received 🎬';
  return [text(msg)];
}

// ── Audio / Voice ─────────────────────────────────────
if (msgType === 'audio' || msgType === 'ptt') {
  const msg = msgType === 'ptt'
    ? 'تم استلام رسالتك الصوتية 🎙️\nVoice message received 🎙️'
    : 'تم استلام الملف الصوتي 🎵\nAudio file received 🎵';
  return [text(msg)];
}

// ── Document ──────────────────────────────────────────
if (msgType === 'document') {
  const name = fileName || 'document';
  return [text(`تم استلام الملف 📄: ${name}\nDocument received 📄: ${name}`)];
}

// ── Sticker ───────────────────────────────────────────
if (msgType === 'sticker') {
  return [text('تم استلام الملصق 🎯\nSticker received 🎯')];
}

// ── Location ──────────────────────────────────────────
if (msgType === 'location') {
  const maps = `https://maps.google.com/?q=${lat},${lng}`;
  const desc = loc ? ` — ${loc}` : '';
  return [text(`تم استلام موقعك 📍${desc}\n${maps}\nLocation received 📍`)];
}

// ── Fallback ──────────────────────────────────────────
return [text('تم استلام رسالتك ✅')];

// ── Error Logger ──
const err    = $json || {};
const status = err.statusCode || err.status || 'unknown';
const msg    = JSON.stringify(err.body || err.message || err);
console.error('[WhatsApp Bot] Send failed — HTTP ' + status + ': ' + msg);
return [{ error: true, status, message: msg }];
